import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as a,c as s,a as i,b as l,e as r,f as e}from"./app-f9dd4f6a.js";const p={},g=i("h1",{id:"计算机网络",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#计算机网络","aria-hidden":"true"},"#"),l(" 计算机网络")],-1),u={href:"https://www.bilibili.com/video/BV1c4411d7jb?vd_source=1bbc8a9be9ea748de8b1d19c0446cafd",target:"_blank",rel:"noopener noreferrer"},h=e('<p>[TOC]</p><h1 id="第一章-概述" tabindex="-1"><a class="header-anchor" href="#第一章-概述" aria-hidden="true">#</a> 第一章 概述</h1><h2 id="_1-2-因特网概述" tabindex="-1"><a class="header-anchor" href="#_1-2-因特网概述" aria-hidden="true">#</a> 1.2 因特网概述</h2><p>网络、互联网和因特网</p><ul><li><p>网络（Network）有若干结点（Node）和连接这些结点的链路（Link）组成。</p></li><li><p>多个网络还可以通过路由器互连起来，这样就构成了一个覆盖范围更大的网络，即互联网。因此互联网是“网络的网络”。</p></li><li><p>因特网（Internet）是世界上最大的互连网络。</p></li><li><p>internet和Internet区分：</p><ul><li>internet（互联网）是一个通用名词，泛指有多个计算机网络互连而成的网络，在这些网络之间的通信协议可以是任意的。</li><li>Internet（因特网）是一个专有名词，特指当前全球最大的、开放的、有众多网络互相连接而成的特定的计算机网络，采用TCP/IP协议族作为通信的规则，前身是ARPANET。</li></ul></li></ul><p>因特网发展的三个阶段：</p><ul><li>1969，<strong>第一个分组交换网ARPANET</strong>，1983年TCPIP协议成为ARPANET的标准协议。</li><li>1985，NSF围绕六个大型计算机中心建设NSFNET，主干网、地区网、校园网三级结构的互联网。</li><li>1993，政府不再负责因特网运营，让各种因特网服务提供者ISP来运营。</li></ul><p>因特网服务提供者ISP(Internet Service Provider)</p><p>ISP可以从因特网管理机构申请到成块的IP地址，同时拥有通信线路以及路由器等联网设备，任何机构或者个人通过向ISP交纳费用，就可以从所需要的IP地址，有了ip地址就可以上网了。我国的ISP有中国移动中国联通中国电信。</p><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/image-20231018120150942.png" alt="基于ISP的三层结构的因特网" style="zoom:50%;"><p>因特网的标准化工作</p><ul><li>标准指定的特点是：面向大众</li><li>RFC request for comments 技术文档</li><li>因特网协会ISOC是一个国际型组织，负责对因特网全面管理。 <ul><li>因特网体系结构委员会IAB，负责管理因特网有关协议的开发。</li><li>因特网工程部IETF，负责研究中短期工程问题，主要针对协议的开发和标准化。</li><li>因特网研究部IRTF，从事理论方面的研究和开发一些需要长期考虑的问题。</li></ul></li></ul><p>制定因特网的正式标准经过四个阶段：</p><ol><li>因特网草案</li><li>建议标准 RFC文档</li><li>草案标准</li><li>因特网标准</li></ol><p>因特网的组成</p><ul><li>边缘部分：由所有连接在因特网上的主机组成，这部分是用户直接使用的，用来进行通信和资源共享。</li><li>核心部分：由大量网络和连接这些网络的路由器组成，这部分是为边缘部分提供服务的。</li></ul><h2 id="_1-3-三种交换方式" tabindex="-1"><a class="header-anchor" href="#_1-3-三种交换方式" aria-hidden="true">#</a> 1.3 三种交换方式</h2><p>电路交换</p><p>电话交换机接通电话线的方式称为电路交换</p><p>从通信资源的分配角度看，交换就是按照某种方式动态的分配传输线路的资源。</p><p>电路交换的三个步骤：</p><ol><li>建立连接，分配通信资源</li><li>通话，一直占用通信资源</li><li>释放连接，归还通信资源</li></ol><p>分组交换</p><p>在因特网中，<strong>路由器负责分组交换</strong>，也就是分组交换机，连接各个网络，转发接收到的分组。</p><p>发送方发送消息，这个<strong>消息整个被称为报文</strong>，发送前划分报文为等长数据段，在每个数据段前加上首部信息，<strong>构成分组（包）</strong>，首部中包含分组传输目的地址，路由器接收分组，存储分组，检查首部，按照首部中的目的地址查表转发。</p><p>发送方职责：构造分组、发送分组</p><p>路由器职责：缓存分组、转发分组</p><p>接收方职责：接收分组、还原报文</p><p>报文交换一般被分组交换所取代</p><p>三者对比</p><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/image-20231018124141084.png" alt="电路交换、报文交换、分组交换对比" style="zoom:67%;"><h2 id="_1-4计算机网络的定义和分类" tabindex="-1"><a class="header-anchor" href="#_1-4计算机网络的定义和分类" aria-hidden="true">#</a> 1.4计算机网络的定义和分类</h2><ul><li><p>计算机网络的精确定义并未统一</p></li><li><p>计算机网络的最简单的定义是：一些互相连接的、自治的计算机的集合</p><ul><li>互连：是指计算机之间可以通过有线或无线的方式进行数据通信</li><li>自治：是指独立的计算机，它有自己的硬件和软件，可以单独运行使用</li><li>集合：是指至少需要两台计算机</li></ul></li><li><p>计算机网络的较好的定义是：计算机网络主要是由一些通用的、可编程的硬件互连而成的，而这些硬件并非专门用来实现某一特定目的（例如，传送数据或视频信号）。这些可编程的硬件能够用来传送多种不同类型的数据，并能支持广泛的和日益增长的应用</p><ul><li>计算机网络所连接的硬件，并不限于一般的计算机，而是包括了智能手机等智能硬件</li><li>计算机网络并非专门用来传送数据，而是能够支持很多种的应用（包括今后可能出现的各种应用）</li></ul></li></ul><p>计算机网络的分类：</p><ul><li><p>按交换技术分类：</p><ul><li><p>电路交换网络</p></li><li><p>报文交换网络</p></li><li><p>分组交换网络</p></li></ul></li><li><p>按使用者分类：</p><ul><li><p>公用网</p></li><li><p>专用网</p></li></ul></li><li><p>按传输介质分类：</p><ul><li><p>有线网络</p></li><li><p>无线网络</p></li></ul></li><li><p>按覆盖范围分类：</p><ul><li><p>广域网WAN</p></li><li><p>城域网MAN</p></li><li><p>局域网LAN</p></li><li><p>个域网PAN</p></li></ul></li><li><p>按网络拓扑分类：</p><ul><li><p>总线型</p></li><li><p>星型网络</p></li><li><p>环型网络</p></li><li><p>网状型网络</p></li></ul></li></ul><h2 id="_1-5-计算机网络的性能指标" tabindex="-1"><a class="header-anchor" href="#_1-5-计算机网络的性能指标" aria-hidden="true">#</a> 1.5 计算机网络的性能指标</h2><ul><li><p>比特：计算机中的数据量单位，一个比特等于二进制数字中的一个1或0。</p><ul><li>常用数据量单位：字节</li><li>单位换算：1Byte = 8bit，1KB = 2的10次方B ，1MB = 2的20次方 B，1GB = 2的30次方B，1TB = 2的40次方B</li></ul></li><li><p>速率：连接在计算机网络上的主机在数字信道上传送比特的速率，称为<strong>比特率</strong>或<strong>数据率</strong>。</p><ul><li>常用的数据率单位：比特每秒（bit/s、b/s、bps）</li><li>单位换算：1 kb/s = 10的三次方b/s，1Mb/s = 10的六次方b/s，1Gb/s = 10的九次方b/s，1Tb/s = 10的十二次方b/s</li></ul></li></ul><p>带宽：</p><ul><li>带宽在模拟信号系统中的意义： <ul><li><strong>信号</strong>所包含的各种不同频率成分所占据的<strong>频率范围</strong></li><li>单位：Hz、kHz、MHz、GHz</li></ul></li><li>带宽在计算机网络中的意义： <ul><li>用来表示网络的<strong>通信线路</strong>所能传送数据的能力，因此网络带宽表示在单位时间内从网络中的某一点到另一点所能通过的“<strong>最高数据率</strong>“</li><li>单位：（与上述速率单位一致）</li></ul></li></ul><blockquote><p>其实，带宽的这两种表述之间有着密切的联系。一条通信线路的“频带宽度”越宽，其所传输数据的“最高数据率”也越高</p></blockquote><p>吞吐量：</p><ul><li>吞吐量：吞吐量表示在<strong>单位时间内通过某个网络（或信道、接口）的数据量</strong></li><li>吞吐量<strong>受网络的带宽或额定速率的限制</strong></li></ul><p>时延：</p><ul><li>发送时延 = 分组长度 / 发送速率</li><li>传播时延 = 信道长度 / 电磁波传播速率</li><li>处理时延 = 一般不计算</li></ul><p>时延带宽积：</p><ul><li>计算：传播时延 * 带宽</li><li>若发送端连续发送数据，则在所发送的第一个比特即将到达终点时，发送端就已经发送了时延带宽积个比特</li><li>链路的时延带宽积又称为<strong>以比特为单位的链路长度</strong></li></ul><p>往返时间：</p><ul><li>多数情况下，因特网上的信息不仅仅是单方向传输，而是双向交互</li><li>因此，**往返时间RTT（Round-Trip Time）**是一个重要指标</li><li>时间为：发送端发送分组开始到接收到接收端传回的确认信息为止</li></ul><p>利用率：</p><ul><li>信道利用率：某信道有百分之几的时间是被利用的（有数据通过）</li><li>网络利用率：全网络的信道利用率的加权平均值</li><li><strong>信道利用率并非越高越好</strong>，通信存在排队，利用率高也意味着排队产生的时延久</li><li><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/e8af8dcf722c70316106dc95911b2c0d.png" alt="img" style="zoom:50%;"> - 当网络的利用率达到50%时，时延便要加倍 - 当网络的利用率超过50%时，时延急剧增大 - 当网络的利用率接近100%时，时延趋于无穷大 - 因此，一些拥有较大主干网的ISP通常会控制它们的信道利用率不超过50%。若超过了，就准备扩容，增大线路的带宽 </li></ul><p>丢包率：</p><ul><li>丢包率即分组丢失率，指在一定的时间范围内，传输过程中<strong>丢失的分组数量与总分组数量的比率</strong></li><li>丢包率具体可分为接口丢包率、结点丢包率、链路丢包率、路径丢包率、网络丢包率等</li><li>丢包率使网络运维人员非常关心的一个网络性能指标，但对于普通用户来说通常意识不到网络丢包</li><li>分组丢失主要的两种情况： <ul><li>分组在传输过程中出现<strong>误码</strong>，被结点丢弃</li><li>在通信量较大时可能造成<strong>网络拥塞</strong>，分组到达一台队列已满的分组交换机时被丢弃</li></ul></li><li>丢包率反映了网络的拥塞情况： <ul><li>无拥塞时路径丢包率为 0</li><li>轻度拥塞时路径丢包率为 1% - 4%</li><li>严重拥塞时路径丢包率为 5% - 15%</li></ul></li></ul><h2 id="_1-6-计算机网络体系结构" tabindex="-1"><a class="header-anchor" href="#_1-6-计算机网络体系结构" aria-hidden="true">#</a> 1.6 计算机网络体系结构</h2><p>三种分层：</p><figure><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/image-20231116153359818.png" alt="image-20231116153359818" tabindex="0" loading="lazy"><figcaption>image-20231116153359818</figcaption></figure><p>为什么要分层？</p>',56),c={href:"https://javaguide.cn/cs-basics/network/other-network-questions.html#%E7%BD%91%E7%BB%9C%E5%88%86%E5%B1%82%E6%A8%A1%E5%9E%8B",target:"_blank",rel:"noopener noreferrer"},d=e('<p>说到分层，我们先从我们平时使用框架开发一个后台程序来说，我们往往会按照每一层做不同的事情的原则将系统分为三层（复杂的系统分层会更多）:</p><ol><li>Repository（数据库操作）</li><li>Service（业务操作）</li><li>Controller（前后端数据交互）</li></ol><p><strong>复杂的系统需要分层，因为每一层都需要专注于一类事情。网络分层的原因也是一样，每一层只专注于做一类事情。</strong></p><p>好了，再来说回：“为什么网络要分层？”。我觉得主要有 3 方面的原因：</p><ol><li><strong>各层之间相互独立</strong>：各层之间相互独立，各层之间不需要关心其他层是如何实现的，只需要知道自己如何调用下层提供好的功能就可以了（可以简单理解为接口调用）<strong>。这个和我们对开发时系统进行分层是一个道理。</strong></li><li><strong>提高了灵活性和可替换性</strong>：每一层都可以使用最适合的技术来实现，你只需要保证你提供的功能以及暴露的接口的规则没有改变就行了。并且，每一层都可以根据需要进行修改或替换，而不会影响到整个网络的结构。<strong>这个和我们平时开发系统的时候要求的高内聚、低耦合的原则也是可以对应上的。</strong></li><li><strong>大问题化小</strong>：分层可以将复杂的网络问题分解为许多比较小的、界线比较清晰简单的小问题来处理和解决。这样使得复杂的计算机网络系统变得易于设计，实现和标准化。 <strong>这个和我们平时开发的时候，一般会将系统功能分解，然后将复杂的问题分解为容易理解的更小的问题是相对应的，这些较小的问题具有更好的边界（目标和接口）定义。</strong></li></ol><p>每一层的作用：</p><figure><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/image-20231116153959102.png" alt="image-20231116153959102" tabindex="0" loading="lazy"><figcaption>image-20231116153959102</figcaption></figure><p>专用术语：</p><ul><li>实体：任何可发送或接收信息的硬件或软件进程。</li><li>对等实体：收发双方相同层次中的实体。</li><li>协议：控制两个对等实体进行逻辑通信的规则的集合。</li><li>协议三要素： <ul><li>语法：定义所交换信息的格式</li><li>语义：定义收发双方所要完成的操作</li><li>同步：定义收发双方的时序关系</li></ul></li><li>服务：在协议的控制下，两个对等实体间的逻辑通信使得本层能够向上一层提供服务。 <ul><li>要实现本层协议，还需要使用下面一层所提供的服务。</li><li>协议是水平的，服务是垂直的。</li><li>下层协议对上层实体透明。</li></ul></li><li>服务访问点：在同一系统中相邻两层的实体交换信息的逻辑接口，用于区分不同的服务类型。 <ul><li>数据链路层的服务访问点为帧的”类型“字段</li><li>网络层的服务访问点为IP数据报首部中的协议字段</li><li>运输层的服务访问点为端口号</li></ul></li><li>服务原语：上层使用下层所提供的服务必须通过与下层交换一些命令，这些命令被称为服务原语。</li><li>协议数据单元PDU：对等层次之间传送的数据包称为该层的协议数据单元</li><li>服务数据单元SDU：同一系统内，层与层之间交换的数据包称为服务数据单元</li></ul><figure><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/image-20231116161104346.png" alt="image-20231116161104346" tabindex="0" loading="lazy"><figcaption>image-20231116161104346</figcaption></figure><h1 id="第二章-物理层" tabindex="-1"><a class="header-anchor" href="#第二章-物理层" aria-hidden="true">#</a> 第二章 物理层</h1><h2 id="_2-1-物理层的基本概念" tabindex="-1"><a class="header-anchor" href="#_2-1-物理层的基本概念" aria-hidden="true">#</a> 2.1 物理层的基本概念</h2><ul><li>物理层考虑的是怎样才能在连接各种计算机的传输媒体上传输数据比特流。</li><li>物理层为数据链路层屏蔽了各种传输媒体的差异，使数据链路层只需要考虑如何完成本层的协议和服务，而不必考虑网络具体的传输媒体是什么。</li><li>物理层协议的主要任务： <ul><li>机械特性：指明接口所用接线器的<strong>形状</strong>和<strong>尺寸</strong>、<strong>引脚数目</strong>和<strong>排列</strong>、<strong>固定</strong>和<strong>锁定</strong>装置</li><li>电气特性：指明在接口电缆的各条线上出现的<strong>电压的范围</strong></li><li>功能特性：指明某条线上出现的某一电平的<strong>电压表示何种意义</strong></li><li>过程特性：指明对于不同功能的各种可能<strong>事件的出现顺序</strong></li></ul></li></ul><h2 id="_2-2-物理层的传输媒体" tabindex="-1"><a class="header-anchor" href="#_2-2-物理层的传输媒体" aria-hidden="true">#</a> 2.2 物理层的传输媒体</h2><ul><li>导引型传输媒体： <ul><li>双绞线</li><li>同轴电缆</li><li>光纤</li></ul></li><li>非导引型传输媒体 <ul><li>无线电波</li><li>微波</li><li>红外线</li><li>可见光</li></ul></li></ul><blockquote><p>集线器：<br> 集线器的英文称为“<strong>Hub</strong>”。“Hub”是“中心”的意思，集线器的主要功能是对接收到的信号进行<strong>再生整形放大</strong>，以扩大网络的传输距离，同时把所有节点集中在以它为中心的节点上。它工作于OSI(开放系统互联参考模型)参考模型第一层，即“<strong>物理层</strong>”。集线器与网卡、网线等传输介质一样，属于局域网中的基础设备，<strong>采用CSMA/CD（即带冲突检测的载波监听多路访问技术)介质访问控制机制</strong>。集线器每个接口简单的收发比特，收到1就转发1，收到0就转发0，不进行碰撞检测。集线器（hub）属于纯硬件网络底层设备，基本上不具有类似于交换机的&quot;智能记忆&quot;能力和&quot;学习&quot;能力。它也不具备交换机所具有的MAC地址表，所以它发送数据时都是没有针对性的，而是采用广播方式发送。也就是说当它要向某节点发送数据时，不是直接把数据发送到目的节点，而是把数据包发送到与集线器相连的所有节点，如图所示，简单明了。HUB是一个多端口的转发器，当以HUB为中心设备时，网络中某条线路产生了故障，并不影响其它线路的工作。所以HUB在局域网中得到了广泛的应用。大多数的时候它用在星型与树型网络拓扑结构中，以RJ45接口与各主机相连（也有BNC接口），HUB按照不同的说法有很多种类。</p></blockquote><h2 id="_2-3-传输方式" tabindex="-1"><a class="header-anchor" href="#_2-3-传输方式" aria-hidden="true">#</a> 2.3 传输方式</h2><ul><li>串行传输和并行传输 <ul><li>远距离传输 如计算机网络通常采用串行传输</li><li>计算机内部通常采用并行传输</li></ul></li><li>同步传输与异步传输</li><li>单向通信、半双工通信、全双工通信</li></ul><h2 id="_2-4-编码与调制" tabindex="-1"><a class="header-anchor" href="#_2-4-编码与调制" aria-hidden="true">#</a> 2.4 编码与调制</h2><figure><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/03067e96ff4116bcfecd06aaff715a35.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>常用编码： <ul><li>不归零编码</li><li>归零编码</li><li>曼彻斯特编码</li><li>差分曼彻斯特编码</li></ul></li><li>常用调制： <ul><li>基本调制方法：调幅、调频、调相，1个码元只能包含一个比特信息</li><li>混合调制</li></ul></li></ul><h2 id="_2-5-信道的极限容量" tabindex="-1"><a class="header-anchor" href="#_2-5-信道的极限容量" aria-hidden="true">#</a> 2.5 信道的极限容量</h2><ul><li><p>失真</p><img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/image-20231116194246009.png" alt="image-20231116194246009" style="zoom:50%;"></li><li><p>失真因素：</p><ul><li>码元传输速率</li><li>信号传输速率</li><li>噪声干扰</li><li>传输媒体质量</li></ul></li><li><p>奈氏准则<img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/5363a30c9be1898eb5b869184422a65f.png" alt="image-20211009110610317" loading="lazy"></p></li><li><p>香农定理<img src="https://raw.githubusercontent.com/DropTheChains/blog-img/main/img/67afff4addf1526ff251f57ced649fa1.png" alt="image-20211009111001313" loading="lazy"></p></li><li><p>在信道带宽一定的情况下，根据奈氏准则和香农公式，要想<strong>提高信息的传输速率</strong>就必须采用<strong>多元制</strong>（更好的调制方法）和努力<strong>提高信道中的信噪比</strong></p></li><li><p>自从香农公式发表后，各种<strong>新的信号处理和调制方法就不断出现</strong>，其目的都是为了尽可能<strong>接近香农公式给出的传输速率极限</strong></p></li></ul>',23);function m(b,f){const t=o("ExternalLinkIcon");return a(),s("div",null,[g,i("p",null,[l("视频教程：【计算机网络微课堂（湖科大教书匠）】"),i("a",u,[l("https://www.bilibili.com/video/BV1c4411d7jb?vd_source=1bbc8a9be9ea748de8b1d19c0446cafd"),r(t)])]),h,i("p",null,[l("链接："),i("a",c,[l("计算机网络常见面试题总结(上) | JavaGuide(Java面试 + 学习指南)"),r(t)])]),d])}const B=n(p,[["render",m],["__file","计算机网络.html.vue"]]);export{B as default};
